  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum Role {\n  CLIENT\n  HOTEL_MANAGER\n  FLIGHT_MANAGER\n  ADMIN\n}\n\nenum ReservationStatus {\n  PENDING\n  CONFIRMED\n  CANCELLED\n}\n\nenum PaymentStatus {\n  PENDING\n  PAID\n  REFUNDED\n  FAILED\n}\n\nenum FlightStatus {\n  SCHEDULED\n  BOARDING\n  DEPARTED\n  ARRIVED\n  CANCELLED\n  DELAYED\n}\n\nenum RoomType {\n  SINGLE\n  DOUBLE\n  SUITE\n  FAMILY\n  DELUXE\n}\n\n// ========================\n// USER\n// ========================\nmodel User {\n  id           String   @id @default(cuid())\n  email        String   @unique\n  passwordHash String\n  role         Role     @default(CLIENT)\n  isBlocked    Boolean  @default(false)\n  firstName    String\n  lastName     String\n  phone        String?\n  avatarUrl    String?  @db.Text\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  flightReservations FlightReservation[]\n  hotelReservations  HotelReservation[]\n  reviews            Review[]\n  notifications      Notification[]\n  managedHotels      Hotel[]             @relation(\"HotelManager\")\n  managedAirlines    AirlineCompany[]    @relation(\"AirlineManager\")\n  passwordResets     PasswordReset[]\n\n  @@map(\"users\")\n}\n\nmodel PasswordReset {\n  id        String   @id @default(cuid())\n  userId    String\n  token     String   @unique\n  expiresAt DateTime\n  used      Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"password_resets\")\n}\n\n// ========================\n// AIRLINE & FLIGHT\n// ========================\nmodel AirlineCompany {\n  id        String   @id @default(cuid())\n  name      String\n  logoUrl   String?  @db.Text\n  country   String\n  iataCode  String   @unique\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  flights  Flight[]\n  managers User[]   @relation(\"AirlineManager\")\n\n  @@map(\"airline_companies\")\n}\n\nmodel Flight {\n  id             String       @id @default(cuid())\n  flightNumber   String       @unique\n  origin         String\n  destination    String\n  departureTime  DateTime\n  arrivalTime    DateTime\n  price          Decimal      @db.Decimal(10, 2)\n  totalSeats     Int\n  availableSeats Int\n  status         FlightStatus @default(SCHEDULED)\n  airlineId      String\n  createdAt      DateTime     @default(now())\n  updatedAt      DateTime     @updatedAt\n\n  airline      AirlineCompany      @relation(fields: [airlineId], references: [id])\n  reservations FlightReservation[]\n  reviews      Review[]\n\n  @@map(\"flights\")\n}\n\n// ========================\n// HOTEL & ROOM\n// ========================\nmodel Hotel {\n  id          String   @id @default(cuid())\n  name        String\n  city        String\n  address     String\n  stars       Int      @default(3)\n  description String?  @db.Text\n  imageUrl    String?  @db.Text\n  amenities   String?  @db.Text // JSON string\n  managerId   String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  manager      User?              @relation(\"HotelManager\", fields: [managerId], references: [id])\n  rooms        Room[]\n  reservations HotelReservation[]\n\n  @@map(\"hotels\")\n}\n\nmodel Room {\n  id            String   @id @default(cuid())\n  hotelId       String\n  roomNumber    String\n  type          RoomType @default(DOUBLE)\n  pricePerNight Decimal  @db.Decimal(10, 2)\n  capacity      Int      @default(2)\n  isAvailable   Boolean  @default(true)\n  description   String?\n  imageUrl      String?  @db.Text\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  hotel        Hotel              @relation(fields: [hotelId], references: [id], onDelete: Cascade)\n  reservations HotelReservation[]\n\n  @@map(\"rooms\")\n}\n\n// ========================\n// RESERVATIONS\n// ========================\nmodel FlightReservation {\n  id            String            @id @default(cuid())\n  userId        String\n  flightId      String\n  seatsBooked   Int               @default(1)\n  totalPrice    Decimal           @db.Decimal(10, 2)\n  status        ReservationStatus @default(PENDING)\n  paymentStatus PaymentStatus     @default(PENDING)\n  seatClass     String            @default(\"ECONOMY\")\n  passengerInfo String?           @db.Text // JSON\n  createdAt     DateTime          @default(now())\n  updatedAt     DateTime          @updatedAt\n\n  user    User     @relation(fields: [userId], references: [id])\n  flight  Flight   @relation(fields: [flightId], references: [id])\n  payment Payment?\n\n  @@map(\"flight_reservations\")\n}\n\nmodel HotelReservation {\n  id              String            @id @default(cuid())\n  userId          String\n  hotelId         String\n  roomId          String\n  checkIn         DateTime\n  checkOut        DateTime\n  totalPrice      Decimal           @db.Decimal(10, 2)\n  status          ReservationStatus @default(PENDING)\n  paymentStatus   PaymentStatus     @default(PENDING)\n  guestCount      Int               @default(1)\n  specialRequests String?           @db.Text\n  createdAt       DateTime          @default(now())\n  updatedAt       DateTime          @updatedAt\n\n  user    User     @relation(fields: [userId], references: [id])\n  hotel   Hotel    @relation(fields: [hotelId], references: [id])\n  room    Room     @relation(fields: [roomId], references: [id])\n  payment Payment?\n\n  @@map(\"hotel_reservations\")\n}\n\n// ========================\n// PAYMENT\n// ========================\nmodel Payment {\n  id                  String        @id @default(cuid())\n  amount              Decimal       @db.Decimal(10, 2)\n  method              String        @default(\"CARD\") // CARD, PAYPAL, etc.\n  status              PaymentStatus @default(PENDING)\n  transactionId       String?       @unique\n  flightReservationId String?       @unique\n  hotelReservationId  String?       @unique\n  cardLast4           String?\n  createdAt           DateTime      @default(now())\n  updatedAt           DateTime      @updatedAt\n\n  flightReservation FlightReservation? @relation(fields: [flightReservationId], references: [id])\n  hotelReservation  HotelReservation?  @relation(fields: [hotelReservationId], references: [id])\n\n  @@map(\"payments\")\n}\n\n// ========================\n// REVIEW\n// ========================\nmodel Review {\n  id        String   @id @default(cuid())\n  userId    String\n  flightId  String\n  rating    Int // 1-5\n  comment   String?  @db.Text\n  createdAt DateTime @default(now())\n\n  user   User   @relation(fields: [userId], references: [id])\n  flight Flight @relation(fields: [flightId], references: [id])\n\n  @@unique([userId, flightId])\n  @@map(\"reviews\")\n}\n\n// ========================\n// NOTIFICATION\n// ========================\nmodel Notification {\n  id        String   @id @default(cuid())\n  userId    String\n  title     String\n  message   String   @db.Text\n  isRead    Boolean  @default(false)\n  type      String   @default(\"INFO\") // INFO, SUCCESS, WARNING, ERROR\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"notifications\")\n}\n",
